---@class StructAchievement
local StructAchievement = LxClass("StructAchievement", nil)
function StructAchievement:StructAchievement()
	self._refId = 0         --成就refId
	self._state = 1         --成就状态,0-未完成,1-可领取,2-已领取
	self._schedule = 0      --当前进度值
	self._goal = 0          --目标值
	self._finishTime = 0	--完成时间（秒）
	self._serverVal = 0		--服务器进度
	self._popup = 0			--是否弹出隐藏框（0=不弹，1=弹
end

function StructAchievement:CreateByPb(pb)
	self._refId 	= pb.refId
	self._state 	= pb.state
	--self._schedule 	= pb.schedule
	--self._goal 		= pb.goal
	self._finishTime = pb.finishTime
	self._serverVal = pb.serverVal
	self._popup 	= pb.popup

	local schedule = pb.schedule
	local goal = pb.goal
	if pb.multiple == 1 then
		schedule = tonumber(schedule)/100
		goal = tonumber(goal)/100
	end

	self._schedule = schedule
	self._goal = goal
end

function StructAchievement:GetRefId()
	return self._refId
end

function StructAchievement:GetState()
	return self._state
end
function StructAchievement:SetState(state)
	self._state = state
end

function StructAchievement:GetSchedule()
	return self._schedule
end

function StructAchievement:GetGoal()
	return self._goal
end

function StructAchievement:GetFinishTime()
	return self._finishTime
end

function StructAchievement:GetServerVal()
	return self._serverVal
end

function StructAchievement:GetPopup()
	return self._popup
end

function StructAchievement:SetType(type)
	self._type = type
end

function StructAchievement:GetType()
	return self._type
end

function StructAchievement:SetSort(sort)
	self._sort = sort
end

function StructAchievement:GetSort()
	return self._sort
end

function StructAchievement:SetHide(hide)
	self._isHide = hide == 1
end

function StructAchievement:GetHide()
	return self._isHide or false
end

function StructAchievement:SetProgressValue(progressValue)
	if not self._goal or tonumber(self._goal) == 0 then
		return
	end

	if not progressValue then
		progressValue = tonumber(self._schedule) / tonumber(self._goal)
	end

	self._progressValue = progressValue
end

function StructAchievement:GetProgressValue()
	return self._progressValue or 0
end

return StructAchievement